7.10 Interactive: Join Type Explorer

viewof leftSize  = Inputs.range([1, 20], {value: 8,  step: 1, label: "Left table rows"})
viewof rightSize = Inputs.range([1, 20], {value: 6,  step: 1, label: "Right table rows"})
viewof matchPct  = Inputs.range([0, 100], {value: 50, step: 5, label: "% rows with a match"})
viewof joinType  = Inputs.select(
  ["INNER JOIN", "LEFT OUTER JOIN", "RIGHT OUTER JOIN", "FULL OUTER JOIN", "CROSS JOIN"],
  {value: "INNER JOIN", label: "Join type"}
)

// Compute result sizes
{
  const matched  = Math.round(Math.min(leftSize, rightSize) * matchPct / 100);
  const leftOnly = leftSize  - matched;
  const rightOnly= rightSize - matched;

  let resultRows;
  if      (joinType === "INNER JOIN")       resultRows = matched;
  else if (joinType === "LEFT OUTER JOIN")  resultRows = matched + leftOnly;
  else if (joinType === "RIGHT OUTER JOIN") resultRows = matched + rightOnly;
  else if (joinType === "FULL OUTER JOIN")  resultRows = matched + leftOnly + rightOnly;
  else                                      resultRows = leftSize * rightSize;  // CROSS

  const breakdown = joinType === "CROSS JOIN"
    ? `${leftSize} × ${rightSize} = ${resultRows}`
    : `Matched: ${matched}  |  Left-only: ${leftOnly}  |  Right-only: ${rightOnly}`;

  return htl.html`
    &lt;div style="font-family:monospace; background:#f4f4f4; padding:1rem; border-radius:8px;"&gt;
      &lt;b&gt;${joinType}&lt;/b&gt;&lt;br/&gt;
      Left table: &lt;b&gt;${leftSize}&lt;/b&gt; rows &nbsp;|&nbsp;
      Right table: &lt;b&gt;${rightSize}&lt;/b&gt; rows &nbsp;|&nbsp;
      Match rate: &lt;b&gt;${matchPct}%&lt;/b&gt;&lt;br/&gt;
      ${breakdown}&lt;br/&gt;&lt;br/&gt;
      &lt;b style="font-size:1.4em;"&gt;Result set: ${resultRows} rows&lt;/b&gt;
    &lt;/div&gt;`;
}












