      &lt;h4 style="margin:0 0 12px"&gt;Cost at ${rowCount.toLocaleString()} rows&lt;/h4&gt;
      &lt;table style="width:100%;border-collapse:collapse"&gt;
        &lt;tr style="background:#f0f4f8"&gt;
          &lt;th style="padding:8px;text-align:left"&gt;Method&lt;/th&gt;
          &lt;th style="padding:8px;text-align:right"&gt;Estimated time&lt;/th&gt;
          &lt;th style="padding:8px;text-align:left"&gt;Complexity&lt;/th&gt;
        &lt;/tr&gt;
        &lt;tr&gt;
          &lt;td style="padding:8px"&gt;📄 Full file scan (no index)&lt;/td&gt;
          &lt;td style="padding:8px;text-align:right;color:#c0392b;font-weight:bold"&gt;${fmt(scanMs)}&lt;/td&gt;
          &lt;td style="padding:8px"&gt;O(n)&lt;/td&gt;
        &lt;/tr&gt;
        &lt;tr style="background:#f0fff4"&gt;
          &lt;td style="padding:8px"&gt;🌳 B+ tree index lookup&lt;/td&gt;
          &lt;td style="padding:8px;text-align:right;color:#27ae60;font-weight:bold"&gt;${fmt(indexMs)}&lt;/td&gt;
          &lt;td style="padding:8px"&gt;O(log n)&lt;/td&gt;
        &lt;/tr&gt;
      &lt;/table&gt;
      &lt;p style="margin-top:10px;font-size:0.9em;color:#444"&gt;
        Index is &lt;strong&gt;${speedup}×&lt;/strong&gt; faster at this table size.
      &lt;/p&gt;
    &lt;/div&gt;`;
}

10.8 Interactive: B+ Tree Order Explorer

viewof d = Inputs.range([2, 500], {value: 100, step: 1, label: "Order d (max keys per node)"})
viewof n = Inputs.range([1000, 1_000_000_000], {value: 10_000_000, step: 1000, label: "Number of records n"})

{
  const height   = Math.ceil(Math.log(n) / Math.log(2 * d));
  const fanout   = 2 * d;
  const leafCap  = 2 * d;   // simplified: each leaf holds up to 2d records
  const numLeaves= Math.ceil(n / leafCap);

  return htl.html`
    &lt;div style="font-family:monospace; background:#f8f8f8; padding:1rem; border-radius:8px; line-height:1.8"&gt;
      &lt;b&gt;B+ Tree with order d = ${d}&lt;/b&gt;&lt;br/&gt;
      Records: &lt;b&gt;${n.toLocaleString()}&lt;/b&gt;&lt;br/&gt;
      Max fan-out (internal nodes): &lt;b&gt;${fanout}&lt;/b&gt; children&lt;br/&gt;
      Estimated leaf pages needed: &lt;b&gt;${numLeaves.toLocaleString()}&lt;/b&gt;&lt;br/&gt;
      &lt;b&gt;Tree height: ${height} levels&lt;/b&gt;&lt;br/&gt;
      Equality search cost: &lt;b&gt;${height} page reads&lt;/b&gt;
    &lt;/div&gt;`;
